// Sugerencias de direcciones via Google Places Autocomplete.
// Input body: { input: string, sessionToken?: string }
// Output: { ok, suggestions: [{description, placeId, main, secondary}] }

const src = $input.first().json;
const body = src.body || src;
const input = (body.input || '').toString().trim();
const sessionToken = (body.sessionToken || '').toString().trim();

// Mínimo 3 caracteres — antes de eso devolvemos lista vacía sin gastar quota.
if (input.length < 3) {
  return [{ json: { ok: true, suggestions: [], reason: 'input_too_short' } }];
}

const safeEnv = (k) => { try { return $env[k]; } catch (_) { return null; } };
const GKEY = safeEnv('GOOGLE_API_KEY');
if (!GKEY) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no configurado' } }];
}

// Places Autocomplete (legacy) — más estable que la nueva Places API y soporta sessionToken para billing.
const qs = {
  input,
  key: GKEY,
  language: 'es',
  components: 'country:co',  // restringido a Colombia
  types: 'address',
};
if (sessionToken) qs.sessiontoken = sessionToken;

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://maps.googleapis.com/maps/api/place/autocomplete/json',
    qs,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
} catch (e) {
  return [{ json: { ok: false, reason: 'network', detail: e?.message || 'unknown' } }];
}

if (resp.statusCode !== 200) {
  return [{ json: { ok: false, reason: 'http_' + resp.statusCode, detail: 'Places API HTTP ' + resp.statusCode } }];
}

const data = resp.body || {};
if (data.status === 'REQUEST_DENIED') {
  return [{ json: { ok: false, reason: 'request_denied',
    detail: data.error_message || 'API key rechazada por Places API. Asegurar que GOOGLE_API_KEY tenga Places API habilitada y restricciones compatibles con uso server-side.' } }];
}
if (data.status === 'OVER_QUERY_LIMIT') {
  return [{ json: { ok: false, reason: 'quota_exceeded', detail: 'Cuota Places API excedida' } }];
}
if (data.status !== 'OK' && data.status !== 'ZERO_RESULTS') {
  return [{ json: { ok: false, reason: 'places_' + (data.status || 'unknown').toLowerCase(),
    detail: data.error_message || ('Places status: ' + data.status) } }];
}

const preds = Array.isArray(data.predictions) ? data.predictions : [];
const suggestions = preds.map(p => ({
  description: p.description,
  placeId: p.place_id,
  main: p.structured_formatting?.main_text || p.description,
  secondary: p.structured_formatting?.secondary_text || '',
  types: Array.isArray(p.types) ? p.types : [],
}));

return [{ json: { ok: true, suggestions, count: suggestions.length } }];
